// ─── HELPERS ────────────────────────────────────────────────────
const totalDucks = (s) => DUCK_TYPES.filter(d => s.ducks[d.id]).length;

// Get effective dive depth for a duck (base + upgrade bonuses)
function getDuckDepth(duckType, state) {
  let depth = duckType.diveDepth;
  for (const up of UPGRADES.filter(u => u.duckId === duckType.id && state.upgrades[u.id] && u.depthAdd)) {
    depth += up.depthAdd;
  }
  return Math.min(depth, 100);
}

// Get effective bonus multiplier for a duck
function getDuckBonus(duckType, state) {
  let bonus = duckType.bonus;
  for (const up of UPGRADES.filter(u => u.duckId === duckType.id && state.upgrades[u.id] && u.bonusAdd)) {
    bonus += up.bonusAdd;
  }
  return bonus;
}

const fmt = (n) => {
  if (n < 1) return n.toFixed(1);
  if (n >= 1e6) return (n / 1e6).toFixed(1) + "M";
  if (n >= 10000) return (n / 1000).toFixed(1) + "K";
  return Math.floor(n).toLocaleString();
};

