// ─── MATH CHALLENGE SYSTEM ──────────────────────────────────────
function generateChallenge(difficulty) {
  // 0 = addition only, 1 = add+sub, 2 = multiplication only, 3 = mixed everything
  const d = Math.min(difficulty, 3);
  let type;
  if (d === 0) type = "add";
  else if (d === 1) type = Math.random() < 0.5 ? "add" : "sub";
  else if (d === 2) type = "mul";
  else type = ["add", "sub", "mul", "multiples"][Math.floor(Math.random() * 4)];
  
  if (type === "add") {
    const a = 2 + Math.floor(Math.random() * 10);
    const b = 1 + Math.floor(Math.random() * 10);
    return { prompt: `${a} + ${b}`, answer: a + b, type: "exact" };
  }
  if (type === "sub") {
    const a = 5 + Math.floor(Math.random() * 15);
    const b = 1 + Math.floor(Math.random() * Math.min(a - 1, 10));
    return { prompt: `${a} − ${b}`, answer: a - b, type: "exact" };
  }
  if (type === "mul") {
    const a = 2 + Math.floor(Math.random() * 8);
    const b = 2 + Math.floor(Math.random() * 8);
    return { prompt: `${a} × ${b}`, answer: a * b, type: "exact" };
  }
  if (type === "multiples") {
    const base = [2, 3, 4, 5, 6][Math.floor(Math.random() * 5)];
    return { prompt: `multiples of ${base}`, answer: base, type: "multiple" };
  }
  return { prompt: "1 + 1", answer: 2, type: "exact" };
}

function isCorrectAnswer(challenge, num) {
  if (!challenge) return false;
  if (challenge.type === "exact") return num === challenge.answer;
  if (challenge.type === "multiple") return num > 0 && num % challenge.answer === 0;
  return false;
}

function generateBubbleNumbers(challenge) {
  // Generate 10 numbers, 4-5 correct answers — enough that you can find them
  const nums = [];
  const correctCount = 4 + Math.floor(Math.random() * 2);
  
  for (let i = 0; i < correctCount; i++) {
    if (challenge.type === "exact") {
      nums.push(challenge.answer);
    } else {
      const mult = (1 + Math.floor(Math.random() * 8)) * challenge.answer;
      nums.push(mult);
    }
  }
  
  // Fill rest with wrong answers (nearby but distinct)
  while (nums.length < 10) {
    let wrong;
    if (challenge.type === "exact") {
      // Wrong answers close to the real answer — makes you think
      const offset = (Math.random() > 0.5 ? 1 : -1) * (1 + Math.floor(Math.random() * 4));
      wrong = challenge.answer + offset;
    } else {
      wrong = 1 + Math.floor(Math.random() * 50);
      if (wrong % challenge.answer === 0) wrong += 1;
    }
    if (wrong > 0 && wrong < 100 && wrong !== challenge.answer) nums.push(wrong);
  }
  
  // Shuffle
  for (let i = nums.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [nums[i], nums[j]] = [nums[j], nums[i]];
  }
  return nums;
}

function checkMilestones(state, setMilestoneQueue) {
  const newMilestones = { ...state.milestones };
  let starsEarned = 0;
  const unlocked = [];
  for (const m of MILESTONES) {
    if (!newMilestones[m.id] && m.check(state)) {
      newMilestones[m.id] = true;
      starsEarned += m.stars;
      unlocked.push(m);
    }
  }
  if (starsEarned > 0) {
    state.milestones = newMilestones;
    state.stars = (state.stars || 0) + starsEarned;
    setMilestoneQueue(q => [...q, ...unlocked]);
  }
  return state;
}

// ─── INITIAL STATE ──────────────────────────────────────────────
function getInitialState() {
  return {
    splashes: 0, totalSplashesEarned: 0, totalPops: 0, stars: 0,
    ducks: {}, upgrades: {},
    milestones: {}, mathLevel: 0,
    lastSaveTime: Date.now(), lastTickTime: Date.now(),
  };
}

// ─── SAVE / LOAD ────────────────────────────────────────────────
const SAVE_KEY = "quack-clicker-save";
async function saveGame(state) {
  try { localStorage.setItem(SAVE_KEY, JSON.stringify({ ...state, lastSaveTime: Date.now() })); }
  catch (e) { console.warn("Save failed:", e); }
}
async function loadGame() {
  try {
    const result = localStorage.getItem(SAVE_KEY);
    if (result) return JSON.parse(result);
  } catch (e) { console.warn("Load failed:", e); }
  return null;
}

